MAP
  DEFRESOLUTION 96
  EXTENT -12000.000 241000.000 -11000.000 242000.000
  FONTSET "font.list"
  IMAGETYPE "png24"
  NAME "MS"
  RESOLUTION 96
  SHAPEPATH ""
  SIZE 1180 847
  STATUS ON
  SYMBOLSET "symbols.sym"
  UNITS METERS

  OUTPUTFORMAT
    NAME "png24"
    MIMETYPE "image/png"
    DRIVER "AGG/PNG"
    EXTENSION "png"
    IMAGEMODE RGB
    TRANSPARENT FALSE
  END # OUTPUTFORMAT

  OUTPUTFORMAT
    NAME "print"
    MIMETYPE "image/png"
    DRIVER "AGG/PNG"
    EXTENSION "png"
    IMAGEMODE RGB
    TRANSPARENT FALSE
  END # OUTPUTFORMAT

  LEGEND
    KEYSIZE 20 10
    KEYSPACING 5 5
    LABEL
      SIZE MEDIUM
      OFFSET 0 0
      SHADOWSIZE 1 1
      TYPE BITMAP
    END # LABEL
    STATUS OFF
  END # LEGEND

  QUERYMAP
    SIZE -1 -1
    STATUS OFF
    STYLE HILITE
  END # QUERYMAP

  SCALEBAR
    INTERVALS 4
    LABEL
      SIZE MEDIUM
      OFFSET 0 0
      SHADOWSIZE 1 1
      TYPE BITMAP
    END # LABEL
    SIZE 200 3
    STATUS OFF
    UNITS MILES
  END # SCALEBAR

  WEB
    METADATA
      "distance_units"	"MS_METERS"
      "mapmanager_version"	"1.0.0.0"
    END # METADATA
  END # WEB

  LAYER
    DATA "test2.tif"
    EXTENT -12000.000 241000.000 -11000.000 242000.000
    NAME "test1"
    PROJECTION
      "AUTO"
    END # PROJECTION
    STATUS ON
    TILEITEM "location"
    TYPE RASTER
    UNITS METERS
  END # LAYER

END # MAP
